import type { DataPoint, TiePoint } from '../types';

/**
 * Calcula el modelo de edad basado en tie-points usando interpolación lineal por tramos
 */
export const applyAgeModel = (dataPoints: DataPoint[], tiePoints: TiePoint[]): DataPoint[] => {
    if (tiePoints.length < 2) return dataPoints;

    const sortedTiePoints = [...tiePoints].sort((a, b) => a.depth - b.depth);

    return dataPoints.map(dp => {
        if (dp.depth === undefined || dp.depth === null) return dp;

        const z = dp.depth;
        let age: number | undefined;

        let p1: TiePoint | null = null;
        let p2: TiePoint | null = null;

        for (let i = 0; i < sortedTiePoints.length; i++) {
            if (sortedTiePoints[i].depth <= z) p1 = sortedTiePoints[i];
            if (sortedTiePoints[i].depth > z) {
                p2 = sortedTiePoints[i];
                break;
            }
        }

        if (p1 && p2) {
            const fraction = (z - p1.depth) / (p2.depth - p1.depth);
            age = p1.age + fraction * (p2.age - p1.age);
        } else if (!p1 && p2) {
            const first = sortedTiePoints[0];
            const second = sortedTiePoints[1];
            const slope = (second.age - first.age) / (second.depth - first.depth);
            age = first.age - (first.depth - z) * slope;
        } else if (p1 && !p2) {
            const last = sortedTiePoints[sortedTiePoints.length - 1];
            const secondLast = sortedTiePoints[sortedTiePoints.length - 2];
            const slope = (last.age - secondLast.age) / (last.depth - secondLast.depth);
            age = last.age + (z - last.depth) * slope;
        }

        return {
            ...dp,
            age: age !== undefined ? parseFloat(age.toFixed(4)) : undefined
        };
    });
};

/**
 * Algoritmo Dynamic Time Warping (DTW) para sintonía orbital
 * Alinea una serie en profundidad con una serie en tiempo
 */
export const performDtwAlignment = (
    targetSeries: { depth: number; value: number }[],
    refSeries: { age: number; value: number }[]
): { depth: number; age: number }[] => {
    const n = refSeries.length;
    const m = targetSeries.length;

    // Normalización Z-score
    const normalize = (vals: number[]) => {
        const avg = vals.reduce((a, b) => a + b, 0) / vals.length;
        const std = Math.sqrt(vals.map(v => Math.pow(v - avg, 2)).reduce((a, b) => a + b, 0) / vals.length);
        return vals.map(v => std === 0 ? 0 : (v - avg) / std);
    };

    const s = normalize(refSeries.map(r => r.value));
    const t = normalize(targetSeries.map(tr => tr.value));

    // Matriz de coste acumulado
    const DTW = Array(n + 1).fill(null).map(() => Array(m + 1).fill(Infinity));
    DTW[0][0] = 0;

    for (let i = 1; i <= n; i++) {
        for (let j = 1; j <= m; j++) {
            const cost = Math.abs(s[i - 1] - t[j - 1]);
            DTW[i][j] = cost + Math.min(DTW[i - 1][j], DTW[i][j - 1], DTW[i - 1][j - 1]);
        }
    }

    // Backtracking para encontrar la ruta óptima
    let i = n, j = m;
    const tiePoints: { depth: number; age: number }[] = [];

    // Solo tomamos puntos significativos (picos/valles locales o cada N puntos)
    // para no saturar el modelo con miles de tie-points
    while (i > 1 && j > 1) {
        if (i % 10 === 0 || (i === n && j === m)) {
            tiePoints.push({ depth: targetSeries[j-1].depth, age: refSeries[i-1].age });
        }
        const minPrev = Math.min(DTW[i - 1][j], DTW[i][j - 1], DTW[i - 1][j - 1]);
        if (minPrev === DTW[i - 1][j - 1]) { i--; j--; }
        else if (minPrev === DTW[i - 1][j]) { i--; }
        else { j--; }
    }

    return tiePoints.reverse();
};

export const calculateSedRates = (tiePoints: TiePoint[]) => {
    const sorted = [...tiePoints].sort((a, b) => a.age - b.age);
    const rates = [];

    for (let i = 0; i < sorted.length - 1; i++) {
        const p1 = sorted[i];
        const p2 = sorted[i + 1];
        const dAge = p2.age - p1.age;
        const dDepth = p2.depth - p1.depth;

        if (dAge <= 0) continue;

        const rate = (dDepth * 100) / dAge; // cm/ka
        rates.push({
            age: (p1.age + p2.age) / 2,
            rate: parseFloat(rate.toFixed(2))
        });
    }
    return rates;
};

import React, { useState, useMemo, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, AreaChart, Area } from 'recharts';
import { MousePointer2, Anchor, Trash2, Save, RefreshCw, TrendingUp, Info, Globe, Activity, Wand2, Loader2 } from 'lucide-react';
import type { Section, TiePoint } from '../types';
import { LR04_DATA } from '../data/lr04';
import { applyAgeModel, calculateSedRates, performDtwAlignment } from '../services/chronologyService';

interface QasTuningWorkspaceProps {
    section: Section;
    proxyLabels: Record<string, string>;
    onSaveModel: (calibratedSection: Section) => void;
    setToast: (toast: any) => void;
}

const QasTuningWorkspace: React.FC<QasTuningWorkspaceProps> = ({ section, proxyLabels, onSaveModel, setToast }) => {
    const [pickingMode, setPickingMode] = useState<'none' | 'depth' | 'age'>('none');
    const [tempTiePoint, setTempTiePoint] = useState<{ depth: number | null, age: number | null }>({ depth: null, age: null });
    const [tiePoints, setTiePoints] = useState<TiePoint[]>(section.ageModel?.tiePoints || []);
    const [activeProxy, setActiveProxy] = useState('delta18O');
    const [viewMode, setViewMode] = useState<'depth' | 'age'>('depth');
    const [isSedRateExpanded, setIsSedRateExpanded] = useState(false);
    const [isAutoTuning, setIsAutoTuning] = useState(false);

    useEffect(() => {
        setTiePoints(section.ageModel?.tiePoints || []);
    }, [section.id]);

    const availableProxies = useMemo(() => {
        const proxies = new Set<string>();
        section.dataPoints.forEach(dp => {
            Object.keys(dp).forEach(k => { if(typeof dp[k] === 'number' && k !== 'depth' && k !== 'age') proxies.add(k); });
        });
        return Array.from(proxies).sort();
    }, [section]);

    const calibratedData = useMemo(() => applyAgeModel(section.dataPoints, tiePoints), [section.dataPoints, tiePoints]);
    const sedRates = useMemo(() => calculateSedRates(tiePoints), [tiePoints]);

    const handleAutoTune = async () => {
        setIsAutoTuning(true);
        setToast({ message: "Iniciando algoritmo DTW (Dynamic Time Warping)...", type: 'info', show: true });

        // Simular latencia para el usuario sienta que la IA está trabajando
        await new Promise(resolve => setTimeout(resolve, 800));

        try {
            const targetSeries = section.dataPoints
                .filter(dp => dp.depth != null && typeof dp[activeProxy] === 'number')
                .map(dp => ({ depth: dp.depth!, value: dp[activeProxy] as number }));

            const refSeries = LR04_DATA.map(r => ({ age: r.age, value: r.d18O }));

            if (targetSeries.length < 10) throw new Error("Datos insuficientes para auto-ajuste.");

            const alignment = performDtwAlignment(targetSeries, refSeries);
            const newTiePoints: TiePoint[] = alignment.map((a, idx) => ({
                id: `dtw-${Date.now()}-${idx}`,
                sectionId: section.id,
                depth: a.depth,
                age: a.age
            }));

            setTiePoints(newTiePoints);
            setToast({ message: "Ajuste orbital automático completado.", type: 'success', show: true });
            setViewMode('age');
        } catch (e: any) {
            setToast({ message: e.message, type: 'error', show: true });
        } finally {
            setIsAutoTuning(false);
        }
    };

    const handleChartClick = (data: any, type: 'depth' | 'age') => {
        if (pickingMode === 'none' || !data) return;
        const val = data.activeLabel;

        if (type === 'depth' && pickingMode === 'depth') {
            setTempTiePoint({ depth: val, age: null });
            setPickingMode('age');
        } else if (type === 'age' && pickingMode === 'age') {
            if (tempTiePoint.depth === null) return;
            const newPoint: TiePoint = {
                id: `tp-${Date.now()}`,
                sectionId: section.id,
                depth: tempTiePoint.depth,
                age: val
            };
            setTiePoints(prev => [...prev, newPoint].sort((a,b) => a.depth - b.depth));
            setTempTiePoint({ depth: null, age: null });
            setPickingMode('depth'); 
        }
    };

    return (
        <div className="flex flex-col gap-4 h-full animate-fade-in text-slate-200">
            {/* Header Dashboard */}
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
                <div className="lg:col-span-3 flex items-center justify-between bg-slate-900/80 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-2xl">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-cyan-500/10 rounded-xl border border-cyan-500/20">
                            <Anchor size={24} className="text-cyan-400" />
                        </div>
                        <div>
                            <h3 className="text-lg font-black tracking-tighter text-white uppercase">Orbital Tuning Lab</h3>
                            <div className="flex gap-3 text-[10px] font-mono text-slate-400 uppercase tracking-widest">
                                <span>Ref: LR04 STACK</span>
                                <span className="text-slate-600">|</span>
                                <span>NÚCLEO: {section.name}</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        <select 
                            value={activeProxy} 
                            onChange={e => setActiveProxy(e.target.value)}
                            className="bg-slate-800 border border-slate-600 rounded-lg px-3 py-1.5 text-sm font-bold text-orange-400 outline-none"
                        >
                            {availableProxies.map(p => <option key={p} value={p}>{proxyLabels[p] || p}</option>)}
                        </select>

                        <button 
                            onClick={handleAutoTune}
                            disabled={isAutoTuning}
                            className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black bg-indigo-600 text-white hover:bg-indigo-500 transition-all disabled:opacity-50"
                        >
                            {isAutoTuning ? <Loader2 size={16} className="animate-spin"/> : <Wand2 size={16} />}
                            AUTO-TUNE (DTW)
                        </button>

                        <button 
                            onClick={() => {
                                const newMode = pickingMode === 'none' ? 'depth' : 'none';
                                setPickingMode(newMode);
                                if (newMode === 'none') setTempTiePoint({ depth: null, age: null });
                            }}
                            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black transition-all ${pickingMode !== 'none' ? 'bg-rose-600 text-white animate-pulse' : 'bg-cyan-600 text-white hover:bg-cyan-500'}`}
                        >
                            <MousePointer2 size={16} />
                            {pickingMode === 'none' ? 'MANUAL PICKING' : 'CANCELAR'}
                        </button>

                        <button 
                            onClick={() => onSaveModel({ ...section, dataPoints: calibratedData, ageModel: { tiePoints } })}
                            className="p-2.5 rounded-xl bg-emerald-600 text-white hover:bg-emerald-500 transition-all"
                        >
                            <Save size={20} />
                        </button>
                    </div>
                </div>

                <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-700 flex items-center justify-around">
                    <div className="text-center">
                        <p className="text-[10px] font-bold text-slate-500 uppercase">Tie-Points</p>
                        <p className="text-2xl font-black text-cyan-400">{tiePoints.length}</p>
                    </div>
                    <div className="h-8 w-px bg-slate-700" />
                    <button onClick={() => setViewMode(viewMode === 'depth' ? 'age' : 'depth')} className="flex flex-col items-center group">
                        <p className="text-[10px] font-bold text-slate-500 uppercase">Vista</p>
                        <span className="text-xs font-black text-emerald-400 flex items-center gap-1"><RefreshCw size={12} /> {viewMode.toUpperCase()}</span>
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 flex-grow overflow-hidden">
                <div className="lg:col-span-3 flex flex-col gap-4 overflow-y-auto">

                    {/* REFERENCIA */}
                    <div className={`bg-slate-950 p-6 rounded-3xl border-2 transition-all relative h-[280px] flex-shrink-0 ${pickingMode === 'age' ? 'border-orange-500 ring-4 ring-orange-500/20' : 'border-slate-800'}`}>
                        <div className="absolute top-4 left-6 z-10 flex items-center gap-2 bg-slate-900/90 px-3 py-1 rounded-full border border-slate-700">
                            <Globe size={12} className="text-cyan-400" />
                            <span className="text-[10px] font-black uppercase text-slate-300">LR04 Benthic Stack (Age domain)</span>
                        </div>
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart data={LR04_DATA} onClick={(d) => handleChartClick(d, 'age')} style={{ cursor: pickingMode === 'age' ? 'crosshair' : 'default' }}>
                                <CartesianGrid strokeDasharray="1 4" vertical={false} stroke="#334155" />
                                <XAxis dataKey="age" hide reversed />
                                <YAxis hide domain={['auto', 'auto']} reversed />
                                <Tooltip contentStyle={{backgroundColor: '#020617', border: 'none'}} labelFormatter={(v)=>`${v} ka`} />
                                <Line type="monotone" dataKey="d18O" stroke="#22d3ee" strokeWidth={3} dot={false} isAnimationActive={false} />
                                {tiePoints.map(tp => (
                                    <ReferenceLine key={tp.id} x={tp.age} stroke="#f43f5e" strokeWidth={2} strokeDasharray="5 5" />
                                ))}
                            </LineChart>
                        </ResponsiveContainer>
                    </div>

                    {/* NÚCLEO */}
                    <div className={`bg-slate-950 p-6 rounded-3xl border-2 transition-all relative h-[400px] flex-shrink-0 ${pickingMode === 'depth' ? 'border-cyan-500 ring-4 ring-cyan-500/20' : 'border-slate-800'}`}>
                        <div className="absolute top-4 left-6 z-10 flex gap-2">
                             <div className="flex items-center gap-2 bg-slate-900/90 px-3 py-1 rounded-full border border-slate-700">
                                <Activity size={12} className="text-orange-400" />
                                <span className="text-[10px] font-black uppercase text-slate-300">
                                    {isSedRateExpanded ? 'Diagnóstico: Sedimentation Rate' : `Núcleo: ${section.name}`}
                                </span>
                            </div>
                        </div>

                        <ResponsiveContainer width="100%" height="100%">
                            {isSedRateExpanded ? (
                                <AreaChart data={sedRates}>
                                    <CartesianGrid strokeDasharray="1 4" stroke="#334155" />
                                    <XAxis dataKey="age" tick={{fill: '#94a3b8', fontSize: 10}} reversed />
                                    <YAxis tick={{fill: '#94a3b8', fontSize: 10}} />
                                    <Area type="stepAfter" dataKey="rate" stroke="#10b981" fill="#10b981" fillOpacity={0.2} strokeWidth={3} />
                                </AreaChart>
                            ) : (
                                <LineChart data={calibratedData} onClick={(d) => handleChartClick(d, 'depth')} style={{ cursor: pickingMode === 'depth' ? 'crosshair' : 'default' }}>
                                    <CartesianGrid strokeDasharray="1 4" stroke="#334155" />
                                    <XAxis dataKey={viewMode === 'depth' ? 'depth' : 'age'} reversed={viewMode === 'age'} tick={{fill: '#94a3b8', fontSize: 11}} />
                                    <YAxis tick={{fill: '#94a3b8', fontSize: 11}} domain={['auto', 'auto']} reversed={activeProxy.includes('delta18O')} />
                                    <Tooltip contentStyle={{backgroundColor: '#020617', border: 'none'}} />
                                    <Line type="monotone" dataKey={activeProxy} stroke="#fb923c" strokeWidth={3} dot={{ r: 3 }} isAnimationActive={false} />
                                    {tiePoints.map(tp => (
                                        <ReferenceLine key={tp.id} x={viewMode === 'depth' ? tp.depth : tp.age} stroke="#f43f5e" strokeWidth={2} />
                                    ))}
                                </LineChart>
                            )}
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Sidebar Controles */}
                <div className="flex flex-col gap-4">
                    <div className="bg-slate-900/60 p-5 rounded-3xl border border-slate-700 flex flex-col h-[320px]">
                        <h4 className="text-xs font-black uppercase text-slate-400 tracking-widest mb-4 flex items-center gap-2">
                            <TrendingUp size={14} className="text-cyan-400"/> TIE-POINTS
                        </h4>
                        <div className="flex-grow overflow-y-auto pr-2 space-y-2">
                            {tiePoints.map((tp) => (
                                <div key={tp.id} className="group flex items-center justify-between bg-slate-800/50 p-3 rounded-2xl border border-slate-700 hover:border-cyan-500/50 transition-all">
                                    <div className="font-mono text-[10px] space-y-0.5">
                                        <div className="text-cyan-400 font-bold">Prof: {tp.depth.toFixed(2)}m</div>
                                        <div className="text-emerald-400 font-bold">Edad: {tp.age.toFixed(1)}ka</div>
                                    </div>
                                    <button onClick={() => setTiePoints(prev => prev.filter(p => p.id !== tp.id))} className="p-2 text-rose-500 hover:bg-rose-500/10 rounded-lg opacity-0 group-hover:opacity-100">
                                        <Trash2 size={14}/>
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="bg-slate-900/60 p-5 rounded-3xl border border-slate-700 shadow-xl flex-grow">
                        <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-3">Tasa Sed. Media</h4>
                        <div className="text-3xl font-black text-emerald-400">
                            {sedRates.length > 0 ? (sedRates.reduce((a,b)=>a+b.rate, 0)/sedRates.length).toFixed(1) : '0'}
                            <span className="text-xs ml-1 text-slate-500">cm/ka</span>
                        </div>
                        <button onClick={()=>setIsSedRateExpanded(!isSedRateExpanded)} className="mt-4 w-full py-2 rounded-xl bg-slate-800 text-[10px] font-bold hover:bg-slate-700 transition-colors uppercase">Ver Gráfico Diagnóstico</button>
                    </div>

                    <div className="p-4 bg-cyan-500/5 rounded-2xl border border-cyan-500/10">
                        <div className="flex gap-3">
                            <Info size={16} className="text-cyan-400 flex-shrink-0" />
                            <p className="text-[9px] text-slate-400 leading-normal">
                                <strong>Tip DTW:</strong> El auto-tuning funciona mejor con δ¹⁸O. Asegúrate de tener al menos 10 puntos de datos para una correlación robusta.
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default QasTuningWorkspace;

import { GoogleGenAI, Modality, Type } from "@google/genai";
import type { Core, Section, DataPoint, Microfossil, PartialMicrofossil, Taxonomy, EcologicalData, TiePoint, SectionFossilRecord, IdentifiedFossil, FeedbackCorrection, ReinforcementFeedback, Source } from '../types';
import type { GenerateContentResponse } from "@google/genai";


// ALWAYS use the pre-configured process.env.API_KEY directly as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateReportCoverImage = async (core: Core): Promise<string | null> => {
    try {
        const prompt = `An abstract, artistic data visualization inspired by oceanic sediment cores from project "${core.project}". Use deep blues, sandy and earthy textures, and clearly defined layered patterns representing geological time. Evoke a sense of scientific discovery and deep-sea exploration. Style: minimal, elegant, high-resolution digital art, abstract background.`;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image', // "Nano Banana"
            contents: {
                parts: [{ text: prompt }],
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return part.inlineData.data;
            }
        }
        return null;
    } catch (error) {
        console.error("Nano Banana (Gemini) Cover Image Generation Error:", error);
        return null;
    }
};

export const identifyFossilsInImage = async (
    base64Image: string,
    mimeType: string,
    context: { geologicalAge?: string; location?: string; visibleFeatures?: string; },
    corrections?: FeedbackCorrection[],
    reinforcements?: ReinforcementFeedback[]
): Promise<IdentifiedFossil[]> => {
    const prompt = `
        Identify the microfossil(s) in this image.
        Context:
        - Geological Age: ${context.geologicalAge || 'Unknown'}
        - Location: ${context.location || 'Unknown'}
        - User Observations: ${context.visibleFeatures || 'None'}

        ${corrections && corrections.length > 0 ? `Corrections from previous attempts (learn from these): ${JSON.stringify(corrections)}` : ''}

        Return a JSON array of identified species. For each, provide:
        - speciesName: Genus and species (e.g., Globigerinoides ruber)
        - confidenceScore: 0-100
        - sourceImageUrl: A URL to a reference image from a reliable scientific source (or null if not found)
        - analysis: Object with 'matchingFeatures' (array of strings) and 'distinguishingFeatures' (array of strings) describing why it matches.
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
            parts: [
                { inlineData: { mimeType: mimeType, data: base64Image } },
                { text: prompt }
            ]
        },
        config: {
            responseMimeType: 'application/json',
            tools: [{ googleSearch: {} }], // Use Google Search to verify species and find reference images
        }
    });

    try {
        const text = response.text || "[]";
        // Clean markdown code blocks if present
        const jsonText = text.replace(/```json|```/g, '').trim();
        return JSON.parse(jsonText);
    } catch (e) {
        console.error("Failed to parse fossil identification", e);
        return [];
    }
};

export const findFossilPublications = async (fossilName: string): Promise<{ summary: string; sources: Source[] }> => {
    const prompt = `Find recent and seminal scientific publications regarding the microfossil species "${fossilName}". Summarize key findings regarding its use as a paleoceanographic proxy.`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
            tools: [{ googleSearch: {} }]
        }
    });

    let sources: Source[] = [];
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        sources = response.candidates[0].groundingMetadata.groundingChunks
            .filter(c => c.web && c.web.uri && c.web.title)
            .map(c => ({ uri: c.web!.uri!, title: c.web!.title! }));
    }

    return {
        summary: response.text || "No summary available.",
        sources
    };
};

export const analyzeFossilAssemblage = async (section: Section, microfossils: Microfossil[]): Promise<string> => {
    const fossilData = section.microfossilRecords.map(r => {
        const fossil = microfossils.find(f => f.id === r.fossilId);
        return {
            species: r.fossilId,
            abundance: r.abundance,
            ecology: fossil?.ecology
        };
    });

    const prompt = `
        Analyze the following microfossil assemblage from a sediment core section (${section.epoch}, ${section.ageRange}).

        Assemblage Data:
        ${JSON.stringify(fossilData, null, 2)}

        Provide a concise paleoenvironmental interpretation. What does this assemblage suggest about:
        1. Sea Surface Temperature (SST)
        2. Productivity / Nutrient levels
        3. Water depth / Dissolution (if relevant)

        Keep it scientific but accessible.
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
    });

    return response.text || "Analysis failed.";
};

export const suggestAgeFromFossils = async (
    records: SectionFossilRecord[],
    allFossils: Microfossil[]
): Promise<{ epoch: string; ageRange: string }> => {
    const speciesList = records.map(r => r.fossilId).join(', ');
    const prompt = `
        Given the following microfossil assemblage: ${speciesList}.
        Suggest the most likely geological Epoch and Age Range (in Ma).
        Return JSON: { "epoch": "string", "ageRange": "string" }
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: 'application/json' }
    });

    try {
        const text = response.text || "{}";
        return JSON.parse(text.replace(/```json|```/g, '').trim());
    } catch (e) {
        console.error("Age suggestion parse error", e);
        return { epoch: '', ageRange: '' };
    }
